"use client";

import { useState, useCallback } from "react";
import { Reservation, User, USER_COLORS } from "@/lib/types";

interface CalendarProps {
  reservations: Reservation[];
  currentUser: User | null;
  onReserve: (date: string) => void;
  onCancel: (reservation: Reservation) => void;
  month: Date;
  onMonthChange: (date: Date) => void;
}

function getDaysInMonth(year: number, month: number): number {
  return new Date(year, month + 1, 0).getDate();
}

function getFirstDayOfMonth(year: number, month: number): number {
  // Return 0 = Monday ... 6 = Sunday
  const day = new Date(year, month, 1).getDay();
  return day === 0 ? 6 : day - 1;
}

function formatDate(year: number, month: number, day: number): string {
  return `${year}-${String(month + 1).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
}

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December",
];

const DAY_NAMES = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];

export default function Calendar({
  reservations,
  currentUser,
  onReserve,
  onCancel,
  month,
  onMonthChange,
}: CalendarProps) {
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const year = month.getFullYear();
  const monthIndex = month.getMonth();
  const daysInMonth = getDaysInMonth(year, monthIndex);
  const firstDay = getFirstDayOfMonth(year, monthIndex);

  const today = new Date();
  const todayStr = formatDate(today.getFullYear(), today.getMonth(), today.getDate());

  const reservationMap = new Map<string, Reservation>();
  reservations.forEach((r) => reservationMap.set(r.date, r));

  const prevMonth = useCallback(() => {
    const d = new Date(year, monthIndex - 1, 1);
    onMonthChange(d);
  }, [year, monthIndex, onMonthChange]);

  const nextMonth = useCallback(() => {
    const d = new Date(year, monthIndex + 1, 1);
    onMonthChange(d);
  }, [year, monthIndex, onMonthChange]);

  const handleDayClick = (dateStr: string) => {
    const reservation = reservationMap.get(dateStr);

    if (reservation) {
      // If it's the current user's reservation, allow cancel
      if (currentUser && reservation.user_id === currentUser.id) {
        setSelectedDate(dateStr);
      }
      return;
    }

    // If no reservation and user is logged in, reserve
    if (currentUser && dateStr >= todayStr) {
      setSelectedDate(dateStr);
    }
  };

  const days: Array<{ day: number | null; dateStr: string }> = [];

  // Empty cells for days before the first day of month
  for (let i = 0; i < firstDay; i++) {
    days.push({ day: null, dateStr: "" });
  }

  // Actual days
  for (let d = 1; d <= daysInMonth; d++) {
    days.push({ day: d, dateStr: formatDate(year, monthIndex, d) });
  }

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-3 bg-sky-700 text-white">
        <button onClick={prevMonth} className="p-1 hover:bg-sky-600 rounded-lg transition-colors">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
        </button>
        <h2 className="text-lg font-semibold">
          {MONTH_NAMES[monthIndex]} {year}
        </h2>
        <button onClick={nextMonth} className="p-1 hover:bg-sky-600 rounded-lg transition-colors">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Day headers */}
      <div className="grid grid-cols-7 bg-gray-50 border-b border-gray-100">
        {DAY_NAMES.map((name) => (
          <div key={name} className="text-center text-xs font-medium text-gray-500 py-2">
            {name}
          </div>
        ))}
      </div>

      {/* Days grid */}
      <div className="grid grid-cols-7 gap-px bg-gray-100">
        {days.map(({ day, dateStr }, i) => {
          if (day === null) {
            return <div key={`empty-${i}`} className="bg-white min-h-[3.5rem]" />;
          }

          const reservation = reservationMap.get(dateStr);
          const isToday = dateStr === todayStr;
          const isPast = dateStr < todayStr;
          const isSelected = dateStr === selectedDate;

          return (
            <button
              key={dateStr}
              onClick={() => handleDayClick(dateStr)}
              disabled={!currentUser || (isPast && !reservation)}
              className={`
                relative bg-white min-h-[3.5rem] p-1 flex flex-col items-center transition-all
                ${isToday ? "ring-2 ring-sky-400 ring-inset" : ""}
                ${isPast && !reservation ? "opacity-40" : ""}
                ${!reservation && currentUser && !isPast ? "hover:bg-sky-50 cursor-pointer" : ""}
                ${isSelected ? "ring-2 ring-sky-500" : ""}
              `}
            >
              <span className={`text-xs font-medium ${isToday ? "text-sky-700" : "text-gray-700"}`}>
                {day}
              </span>

              {reservation && (
                <div
                  className="mt-0.5 w-full rounded-md px-1 py-0.5 text-center"
                  style={{
                    backgroundColor: USER_COLORS[reservation.user_name || ""] + "20",
                    borderLeft: `3px solid ${USER_COLORS[reservation.user_name || ""] || "#6b7280"}`,
                  }}
                >
                  <span className="text-[10px] font-medium leading-tight block truncate" style={{
                    color: USER_COLORS[reservation.user_name || ""] || "#6b7280",
                  }}>
                    {reservation.user_name}
                  </span>
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Action bar */}
      {selectedDate && currentUser && (
        <div className="p-3 bg-sky-50 border-t border-sky-100 flex items-center justify-between">
          {reservationMap.has(selectedDate) ? (
            <>
              <span className="text-sm text-gray-700">
                Cancel your reservation on <strong>{selectedDate}</strong>?
              </span>
              <div className="flex gap-2">
                <button
                  onClick={() => setSelectedDate(null)}
                  className="px-3 py-1.5 text-sm rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50"
                >
                  No
                </button>
                <button
                  onClick={() => {
                    const r = reservationMap.get(selectedDate);
                    if (r) onCancel(r);
                    setSelectedDate(null);
                  }}
                  className="px-3 py-1.5 text-sm rounded-lg bg-red-500 text-white hover:bg-red-600"
                >
                  Cancel it
                </button>
              </div>
            </>
          ) : (
            <>
              <span className="text-sm text-gray-700">
                Reserve <strong>{selectedDate}</strong>?
              </span>
              <div className="flex gap-2">
                <button
                  onClick={() => setSelectedDate(null)}
                  className="px-3 py-1.5 text-sm rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50"
                >
                  No
                </button>
                <button
                  onClick={() => {
                    onReserve(selectedDate);
                    setSelectedDate(null);
                  }}
                  className="px-3 py-1.5 text-sm rounded-lg bg-sky-600 text-white hover:bg-sky-700"
                >
                  Reserve
                </button>
              </div>
            </>
          )}
        </div>
      )}
    </div>
  );
}
