"use client";

import { useState } from "react";
import { FuelLog, User } from "@/lib/types";

interface FuelGaugeProps {
  current: {
    tank_level: number;
    jerry_cans_full: number;
    jerry_cans_empty: number;
  };
  history: FuelLog[];
  currentUser: User | null;
  onUpdate: (tankLevel: number, jerryFull: number, jerryEmpty: number) => void;
}

export default function FuelGauge({ current, history, currentUser, onUpdate }: FuelGaugeProps) {
  const [editing, setEditing] = useState(false);
  const [tankLevel, setTankLevel] = useState(current.tank_level);
  const [jerryFull, setJerryFull] = useState(current.jerry_cans_full);
  const [jerryEmpty, setJerryEmpty] = useState(current.jerry_cans_empty);

  const fillPercent = (current.tank_level / 8) * 100;

  const getFuelColor = (level: number) => {
    if (level <= 2) return "#ef4444"; // red
    if (level <= 4) return "#f59e0b"; // amber
    return "#22c55e"; // green
  };

  const handleSave = () => {
    onUpdate(tankLevel, jerryFull, jerryEmpty);
    setEditing(false);
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-4 space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="font-semibold text-gray-900 flex items-center gap-2">
          <span className="text-lg">⛽</span> Diesel
        </h3>
        <span className="text-sm font-medium text-gray-500">
          {current.tank_level}/8
        </span>
      </div>

      {/* Visual fuel gauge */}
      <div className="relative h-8 bg-gray-100 rounded-full overflow-hidden border border-gray-200">
        <div
          className="absolute inset-y-0 left-0 rounded-full transition-all duration-700 ease-out"
          style={{
            width: `${fillPercent}%`,
            backgroundColor: getFuelColor(current.tank_level),
          }}
        />
        {/* Eighth markers */}
        {[1, 2, 3, 4, 5, 6, 7].map((n) => (
          <div
            key={n}
            className="absolute top-0 bottom-0 w-px bg-gray-300 opacity-50"
            style={{ left: `${(n / 8) * 100}%` }}
          />
        ))}
      </div>

      {/* Jerry cans */}
      <div className="flex items-center gap-4">
        <h4 className="text-sm font-medium text-gray-600 flex items-center gap-1.5">
          <span>🛢️</span> Jerry cans
        </h4>
        <div className="flex gap-3 text-sm">
          <span className="px-2 py-0.5 bg-green-50 text-green-700 rounded-md font-medium">
            {current.jerry_cans_full} full
          </span>
          <span className="px-2 py-0.5 bg-red-50 text-red-700 rounded-md font-medium">
            {current.jerry_cans_empty} empty
          </span>
        </div>
      </div>

      {/* Edit form */}
      {currentUser && !editing && (
        <button
          onClick={() => {
            setTankLevel(current.tank_level);
            setJerryFull(current.jerry_cans_full);
            setJerryEmpty(current.jerry_cans_empty);
            setEditing(true);
          }}
          className="w-full py-2 text-sm font-medium text-sky-600 hover:text-sky-700 hover:bg-sky-50 rounded-lg transition-colors"
        >
          Update after trip
        </button>
      )}

      {editing && (
        <div className="space-y-3 p-3 bg-gray-50 rounded-xl">
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1.5">
              Tank level (0-8 eighths)
            </label>
            <div className="flex gap-1">
              {Array.from({ length: 9 }, (_, i) => (
                <button
                  key={i}
                  onClick={() => setTankLevel(i)}
                  className={`flex-1 py-1.5 text-xs font-medium rounded-md transition-colors ${
                    i === tankLevel
                      ? "bg-sky-600 text-white"
                      : "bg-white border border-gray-200 text-gray-600 hover:bg-gray-50"
                  }`}
                >
                  {i}
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-xs font-medium text-gray-600 mb-1">Full cans</label>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => setJerryFull(Math.max(0, jerryFull - 1))}
                  className="w-8 h-8 rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 flex items-center justify-center"
                >
                  −
                </button>
                <span className="w-8 text-center font-medium">{jerryFull}</span>
                <button
                  onClick={() => setJerryFull(jerryFull + 1)}
                  className="w-8 h-8 rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 flex items-center justify-center"
                >
                  +
                </button>
              </div>
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-600 mb-1">Empty cans</label>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => setJerryEmpty(Math.max(0, jerryEmpty - 1))}
                  className="w-8 h-8 rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 flex items-center justify-center"
                >
                  −
                </button>
                <span className="w-8 text-center font-medium">{jerryEmpty}</span>
                <button
                  onClick={() => setJerryEmpty(jerryEmpty + 1)}
                  className="w-8 h-8 rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 flex items-center justify-center"
                >
                  +
                </button>
              </div>
            </div>
          </div>

          <div className="flex gap-2">
            <button
              onClick={() => setEditing(false)}
              className="flex-1 py-2 text-sm rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50"
            >
              Cancel
            </button>
            <button
              onClick={handleSave}
              className="flex-1 py-2 text-sm rounded-lg bg-sky-600 text-white hover:bg-sky-700 font-medium"
            >
              Save
            </button>
          </div>
        </div>
      )}

      {/* Recent history */}
      {history.length > 0 && (
        <div className="space-y-1">
          <h4 className="text-xs font-medium text-gray-500 uppercase tracking-wide">Recent updates</h4>
          <div className="space-y-1 max-h-32 overflow-y-auto">
            {history.slice(0, 5).map((log) => (
              <div key={log.id} className="flex items-center justify-between text-xs text-gray-500 py-1">
                <span>
                  <strong className="text-gray-700">{log.user_name}</strong> — Tank {log.tank_level}/8
                  {(log.jerry_cans_full > 0 || log.jerry_cans_empty > 0) &&
                    ` · ${log.jerry_cans_full}F/${log.jerry_cans_empty}E cans`
                  }
                </span>
                <span className="text-gray-400 ml-2 shrink-0">
                  {new Date(log.created_at + "Z").toLocaleDateString()}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
