"use client";

import { useState, useEffect, useCallback } from "react";
import Calendar from "@/components/Calendar";
import FuelGauge from "@/components/FuelGauge";
import UsageStats from "@/components/UsageStats";
import UserPicker from "@/components/UserPicker";
import { User, Reservation, FuelLog } from "@/lib/types";

export default function Home() {
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [reservations, setReservations] = useState<Reservation[]>([]);
  const [fuelData, setFuelData] = useState<{
    current: { tank_level: number; jerry_cans_full: number; jerry_cans_empty: number };
    history: FuelLog[];
  }>({
    current: { tank_level: 8, jerry_cans_full: 0, jerry_cans_empty: 0 },
    history: [],
  });
  const [stats, setStats] = useState<Array<{ id: number; name: string; trip_count: number }>>([]);
  const [availableYears, setAvailableYears] = useState<string[]>([]);
  const [month, setMonth] = useState(() => new Date());
  const [statsYear, setStatsYear] = useState(() => new Date().getFullYear());
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState<"calendar" | "fuel" | "stats">("calendar");

  const year = month.getFullYear();
  const monthStr = `${year}-${String(month.getMonth() + 1).padStart(2, "0")}`;

  // Persist user selection
  useEffect(() => {
    if (typeof window !== "undefined") {
      const saved = window.localStorage.getItem("boat-user");
      if (saved) {
        try {
          setCurrentUser(JSON.parse(saved));
        } catch { /* ignore */ }
      }
    }
  }, []);

  const selectUser = (user: User | null) => {
    setCurrentUser(user);
    if (typeof window !== "undefined") {
      if (user) {
        window.localStorage.setItem("boat-user", JSON.stringify(user));
      } else {
        window.localStorage.removeItem("boat-user");
      }
    }
  };

  const fetchAll = useCallback(async () => {
    try {
      const [usersRes, reservationsRes, fuelRes, statsRes] = await Promise.all([
        fetch("/api/users"),
        fetch(`/api/reservations?month=${monthStr}`),
        fetch("/api/fuel"),
        fetch(`/api/stats?year=${statsYear}`),
      ]);

      const [usersData, reservationsData, fuelDataResult, statsData] = await Promise.all([
        usersRes.json(),
        reservationsRes.json(),
        fuelRes.json(),
        statsRes.json(),
      ]);

      setUsers(usersData);
      setReservations(reservationsData);
      setFuelData(fuelDataResult);
      setStats(statsData.stats);
      setAvailableYears(statsData.availableYears);
    } catch (err) {
      console.error("Failed to fetch data:", err);
    } finally {
      setLoading(false);
    }
  }, [monthStr, year, statsYear]);

  useEffect(() => {
    fetchAll();
  }, [fetchAll]);

  const handleReserve = async (date: string) => {
    if (!currentUser) return;
    try {
      const res = await fetch("/api/reservations", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ user_id: currentUser.id, date }),
      });
      if (res.ok) {
        fetchAll();
      } else {
        const data = await res.json();
        alert(data.error || "Failed to reserve");
      }
    } catch {
      alert("Failed to reserve");
    }
  };

  const handleCancel = async (reservation: Reservation) => {
    if (!currentUser) return;
    try {
      const res = await fetch(
        `/api/reservations?id=${reservation.id}&user_id=${currentUser.id}`,
        { method: "DELETE" }
      );
      if (res.ok) {
        fetchAll();
      }
    } catch {
      alert("Failed to cancel");
    }
  };

  const handleFuelUpdate = async (tankLevel: number, jerryFull: number, jerryEmpty: number) => {
    if (!currentUser) return;
    try {
      const res = await fetch("/api/fuel", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          user_id: currentUser.id,
          tank_level: tankLevel,
          jerry_cans_full: jerryFull,
          jerry_cans_empty: jerryEmpty,
        }),
      });
      if (res.ok) {
        fetchAll();
      }
    } catch {
      alert("Failed to update fuel");
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-pulse text-gray-400 text-sm">Loading...</div>
      </div>
    );
  }

  return (
    <div className="flex flex-col min-h-screen max-w-lg mx-auto w-full">
      {/* Header */}
      <header className="px-4 pt-6 pb-3">
        <div className="flex items-center justify-between mb-4">
          <h1 className="text-xl font-bold text-gray-900 flex items-center gap-2">
            <span className="text-2xl">⛵</span> Miloubo
          </h1>
        </div>
        <UserPicker users={users} currentUser={currentUser} onSelect={selectUser} />
      </header>

      {/* Tab navigation */}
      {currentUser && (
        <nav className="px-4 mb-3">
          <div className="flex bg-gray-100 rounded-xl p-1 gap-1">
            {[
              { id: "calendar" as const, label: "Calendar", icon: "📅" },
              { id: "fuel" as const, label: "Fuel", icon: "⛽" },
              { id: "stats" as const, label: "Stats", icon: "📊" },
            ].map(({ id, label, icon }) => (
              <button
                key={id}
                onClick={() => setTab(id)}
                className={`flex-1 py-2 text-sm font-medium rounded-lg transition-colors flex items-center justify-center gap-1.5 ${
                  tab === id
                    ? "bg-white text-gray-900 shadow-sm"
                    : "text-gray-500 hover:text-gray-700"
                }`}
              >
                <span className="text-base">{icon}</span>
                {label}
              </button>
            ))}
          </div>
        </nav>
      )}

      {/* Content */}
      <main className="flex-1 px-4 pb-8 space-y-4">
        {!currentUser && (
          <div className="text-center py-8 text-gray-400 text-sm">
            Select your name above to get started
          </div>
        )}

        {currentUser && tab === "calendar" && (
          <Calendar
            reservations={reservations}
            currentUser={currentUser}
            onReserve={handleReserve}
            onCancel={handleCancel}
            month={month}
            onMonthChange={setMonth}
          />
        )}

        {currentUser && tab === "fuel" && (
          <FuelGauge
            current={fuelData.current}
            history={fuelData.history}
            currentUser={currentUser}
            onUpdate={handleFuelUpdate}
          />
        )}

        {currentUser && tab === "stats" && (
          <UsageStats
            stats={stats}
            year={statsYear}
            availableYears={availableYears}
            onYearChange={setStatsYear}
          />
        )}
      </main>
    </div>
  );
}
